import { Component, OnInit, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule } from '@angular/router';
import { AlumnoService } from '../../../core/services/alumno.service';
import { CursoService } from '../../../core/services/curso.service';
import { AuthService } from '../../../core/services/auth.service';
import { AlumnoDashboardService } from '../../../core/services/alumno-dashboard.service';
import { UserProfile } from '../../../core/models/user-profile.model';

@Component({
  selector: 'app-dashboard-home',
  standalone: true,
  imports: [CommonModule, RouterModule],
  templateUrl: './dashboard-home.component.html',
  styleUrls: ['./dashboard-home.component.css']
})
export class DashboardHomeComponent implements OnInit {
  private authService = inject(AuthService);
  private alumnoService = inject(AlumnoService);
  private cursoService = inject(CursoService);
  private studentService = inject(AlumnoDashboardService);

  profile: UserProfile | null = null;
  isLoading = true;

  // Admin stats
  totalAlumnos = 0;
  totalCursos = 0;
  totalCertificados = 0;

  // Student stats
  studentCursosInscritos = 0;
  studentCursosCompletados = 0;
  studentCertificados = 0;

  ngOnInit(): void {
    this.authService.getProfile().subscribe({
      next: (user) => {
        this.profile = user;
        if (user.rol === 'ADMINISTRADOR') {
          this.loadAdminStats();
        } else {
          this.loadStudentStats();
        }
      },
      error: (err) => {
        console.error('Error fetching profile:', err);
        this.isLoading = false;
      }
    });
  }

  loadAdminStats(): void {
    // Parallel loading of alumnos and courses
    this.alumnoService.listarAlumnos().subscribe({
      next: (alumnos) => {
        this.totalAlumnos = alumnos.length;
        this.cursoService.listarCursos().subscribe({
          next: (cursos) => {
            this.totalCursos = cursos.length;
            this.totalCertificados = 2; // Simulado para Admin
            this.isLoading = false;
          },
          error: () => this.isLoading = false
        });
      },
      error: () => this.isLoading = false
    });
  }

  loadStudentStats(): void {
    this.studentService.getMetrics().subscribe({
      next: (metrics) => {
        this.studentCursosInscritos = metrics.cursosInscritos;
        this.studentCursosCompletados = metrics.cursosCompletados;
        this.studentCertificados = metrics.certificados;
        this.isLoading = false;
      },
      error: (err) => {
        console.error('Error loading student metrics:', err);
        this.isLoading = false;
      }
    });
  }
}
<div class="space-y-8 font-body">
  <!-- Top Welcome Header -->
  <div class="border border-slate-200 p-8 bg-white rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)]">
    <div class="flex items-center gap-4">
      <div class="w-12 h-12 bg-primary/10 border border-primary/20 text-primary flex items-center justify-center rounded-none font-black text-xl">
        A
      </div>
      <div>
        <h1 class="text-2xl font-black text-slate-900 tracking-tight uppercase">Panel de Control General</h1>
        <p class="text-slate-500 text-xs mt-1">Consola administrativa para la gestión del Instituto INSTEIP.</p>
      </div>
    </div>
  </div>

  <!-- Loading State -->
  <div *ngIf="isLoading" class="flex flex-col items-center justify-center p-20 border border-slate-200 bg-white">
    <span class="animate-spin inline-block w-8 h-8 border-4 border-primary border-t-transparent rounded-full mb-3"></span>
    <span class="text-xs font-bold text-slate-500 uppercase tracking-widest">Cargando métricas...</span>
  </div>

  <!-- Dashboard Metrics Grid -->
  <div *ngIf="!isLoading" class="grid grid-cols-1 md:grid-cols-3 gap-6">
    <!-- Metric 1: Total Alumnos -->
    <div class="border border-slate-200 bg-white p-6 rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] flex items-center justify-between">
      <div>
        <span class="text-[10px] font-black text-slate-400 uppercase tracking-widest">Total Alumnos</span>
        <h3 class="text-4xl font-black text-slate-900 mt-2 tracking-tight">{{ totalAlumnos }}</h3>
        <p class="text-[10px] text-emerald-600 font-bold mt-1.5 flex items-center gap-1">
          <span class="w-1.5 h-1.5 bg-emerald-500 rounded-full"></span>
          Suscripciones Activas
        </p>
      </div>
      <div class="w-14 h-14 border border-slate-200 bg-slate-50 flex items-center justify-center text-slate-500 rounded-none">
        <span class="material-symbols-outlined text-3xl">group</span>
      </div>
    </div>

    <!-- Metric 2: Total Cursos -->
    <div class="border border-slate-200 bg-white p-6 rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] flex items-center justify-between opacity-80">
      <div>
        <span class="text-[10px] font-black text-slate-400 uppercase tracking-widest">Total Cursos</span>
        <h3 class="text-4xl font-black text-slate-900 mt-2 tracking-tight">{{ totalCursos }}</h3>
        <p class="text-[10px] text-slate-400 font-semibold mt-1.5">Módulos educativos</p>
      </div>
      <div class="w-14 h-14 border border-slate-200 bg-slate-50 flex items-center justify-center text-slate-400 rounded-none">
        <span class="material-symbols-outlined text-3xl">menu_book</span>
      </div>
    </div>

    <!-- Metric 3: Total Certificados -->
    <div class="border border-slate-200 bg-white p-6 rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] flex items-center justify-between opacity-80">
      <div>
        <span class="text-[10px] font-black text-slate-400 uppercase tracking-widest">Certificados Emitidos</span>
        <h3 class="text-4xl font-black text-slate-900 mt-2 tracking-tight">{{ totalCertificados }}</h3>
        <p class="text-[10px] text-slate-400 font-semibold mt-1.5">Validación Blockchain</p>
      </div>
      <div class="w-14 h-14 border border-slate-200 bg-slate-50 flex items-center justify-center text-slate-400 rounded-none">
        <span class="material-symbols-outlined text-3xl">workspace_premium</span>
      </div>
    </div>
  </div>

  <!-- SPRINT 2 Accomplishment and Tech Overview -->
  <div *ngIf="!isLoading" class="grid grid-cols-1 md:grid-cols-2 gap-6">
    <!-- Quick Access Guide -->
    <div class="border border-slate-200 p-6 bg-white rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)]">
      <h2 class="text-sm font-black text-slate-900 uppercase tracking-wider mb-4 border-b border-slate-100 pb-3">Estado de la Fase Actual</h2>
      <div class="space-y-4 text-xs leading-relaxed text-slate-600">
        <p>Estás visualizando el panel correspondiente al <strong>Sprint 2: Gestión de Alumnos</strong>. Las funcionalidades principales operativas son:</p>
        <ul class="list-disc pl-5 space-y-2">
          <li><strong>Consolidación del CRUD de Alumnos</strong>: Alta, baja, edición y visualización detallada de perfiles de alumnos.</li>
          <li><strong>Asignación de Suscripciones</strong>: Configuración de niveles de acceso (BÁSICO, INTERMEDIO, PREMIUM).</li>
          <li><strong>Control de Estado</strong>: Activación y desactivación instantánea mediante peticiones atómicas en segundo plano.</li>
        </ul>
      </div>
    </div>

    <!-- Technical Infrastructure Summary -->
    <div class="border border-slate-200 p-6 bg-white rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)]">
      <h2 class="text-sm font-black text-slate-900 uppercase tracking-wider mb-4 border-b border-slate-100 pb-3">Infraestructura del Sistema</h2>
      <div class="grid grid-cols-2 gap-4 text-xs">
        <div class="border border-slate-100 p-3 bg-slate-50 rounded-none">
          <span class="block text-[9px] font-bold text-slate-400 uppercase">Base de datos</span>
          <span class="block font-bold text-slate-700 mt-1">PostgreSQL 16</span>
        </div>
        <div class="border border-slate-100 p-3 bg-slate-50 rounded-none">
          <span class="block text-[9px] font-bold text-slate-400 uppercase">Seguridad</span>
          <span class="block font-bold text-slate-700 mt-1">Stateless JWT / Auth</span>
        </div>
        <div class="border border-slate-100 p-3 bg-slate-50 rounded-none">
          <span class="block text-[9px] font-bold text-slate-400 uppercase">Servidor REST</span>
          <span class="block font-bold text-slate-700 mt-1">Spring Boot 3.4</span>
        </div>
